solution:
function maxVowels(s, k) {
  const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
  let c = 0;
  for (let i = 0; i < k; i++) if (vowels.has(s[i])) c++;
  let best = c;
  for (let i = k; i < s.length; i++) {
    if (vowels.has(s[i])) c++;
    if (vowels.has(s[i - k])) c--;
    if (c > best) best = c;
  }
  return best;
}

