}

solution:
function checkInclusion(s1, s2) {
  const k = s1.length;
  if (k > s2.length) return false;
  const need = new Map();
  for (let i = 0; i < s1.length; i++) need.set(s1[i], (need.get(s1[i]) || 0) + 1);
  const win = new Map();
  const eq = (a, b) => {
    if (a.size !== b.size) return false;
    for (const [key, v] of a) if (b.get(key) !== v) return false;
    return true;
  };
  for (let right = 0; right < s2.length; right++) {
    const c = s2[right];
    win.set(c, (win.get(c) || 0) + 1);
    if (right >= k) {
      const lc = s2[right - k];
      win.set(lc, win.get(lc) - 1);
      if (win.get(lc) === 0) win.delete(lc);
    }
    if (right >= k - 1 && eq(win, need)) return true;
  }
  return false;
}
